import json
import boto3
from botocore.exceptions import ClientError

POISON_PHRASES = ['delete_all', 'expose_pii', 'bypass_security']

class SafeActionGroup:
    def __init__(self, lambda_client):
        self.lambda_client = lambda_client

    def invoke_safe(self, function_name: str, payload: dict) -> dict:
        # Pre-validation
        if any(phrase in str(payload).lower() for phrase in POISON_PHRASES):
            return {
                'actionGroup': 'SAFE_ACTION',
                'apiPath': '/error',
                'httpStatusCode': 403,
                'responseBody': {'error': 'Governance violation detected'}
            }

        try:
            response = self.lambda_client.invoke(
                FunctionName=function_name,
                Payload=json.dumps(payload)
            )
            result = json.loads(response['Payload'].read())

            # Post-validation
            if result.get('success'):
                return result
            else:
                return {
                    'actionGroup': 'SAFE_ACTION',
                    'apiPath': '/rejected',
                    'httpStatusCode': 400,
                    'responseBody': {'error': 'Action rejected by governance'}
                }
        except ClientError as e:
            return {
                'actionGroup': 'SAFE_ACTION',
                'apiPath': '/error',
                'httpStatusCode': 500,
                'responseBody': {'error': str(e)}
            }

lambda_client = boto3.client('lambda')
safe_action = SafeActionGroup(lambda_client)

# Use in action group Lambda
def lambda_handler(event, context):
    return safe_action.invoke_safe('YourActionFunction', event)

import boto3
from typing import List

class GovernanceRAG:
    def __init__(self):
        self.bedrock_kb = boto3.client('bedrock-agent-runtime')

    def retrieve_governance_docs(self, query: str, kb_id: str) -> List[dict]:
        response = self.bedrock_kb.retrieve_and_generate(
            input={'text': query},
            retrieveAndGenerateConfiguration={
                'type': 'KNOWLEDGE_BASE',
                'knowledgeBaseConfiguration': {
                    'knowledgeBaseId': kb_id,
                    'modelArn': 'arn:aws:bedrock:us-east-1::foundation-model/anthropic.claude-3-sonnet-20240229-v1:0',
                    'retrievalConfiguration': {
                        'vectorSearchConfiguration': {
                            'numberOfResults': 10,
                            'overrideSearchType': 'HYBRID'
                        }
                    }
                }
            }
        )

        # Filter for governance-relevant results
        governance_docs = [
            cit for cit in response['citations']
            if any(term in cit['content']['text'].lower() 
                   for term in ['policy', 'compliance', 'regulation', 'governance'])
        ]

        return governance_docs

