import boto3
import json
import uuid
from datetime import datetime

class GovernanceSessionManager:
    def __init__(self, table_name: str = 'AgentSessions'):
        self.dynamodb = boto3.resource('dynamodb')
        self.table = self.dynamodb.Table(table_name)

    def get_session_state(self, session_id: str) -> dict:
        try:
            response = self.table.get_item(Key={'sessionId': session_id})
            if 'Item' in response:
                return response['Item']['state']
        except:
            pass
        return {'user_consent_given': False, 'compliance_mode': 'strict'}

    def update_session_state(self, session_id: str, state: dict):
        self.table.put_item(
            Item={
                'sessionId': session_id,
                'state': state,
                'lastUpdated': datetime.utcnow().isoformat(),
                'version': str(uuid.uuid4())
            }
        )

session_mgr = GovernanceSessionManager()

# Before agent invocation
def invoke_with_governance(session_id: str, input_text: str):
    state = session_mgr.get_session_state(session_id)

    if not state.get('user_consent_given'):
        return {'error': 'User consent required'}

    bedrock = boto3.client('bedrock-agent-runtime')
    response = bedrock.invoke_agent(
        agentId='YOUR_AGENT_ID',
        agentAliasId='YOUR_ALIAS_ID',
        sessionId=session_id,
        inputText=input_text
    )

    # Update state post-conversation
    state['last_interaction'] = datetime.utcnow().isoformat()
    session_mgr.update_session_state(session_id, state)

    return response
